import { useQuery } from '@tanstack/react-query';
import React, { useEffect } from 'react'
import { useParams } from 'react-router-dom'
import { Img_URL, fetchSearch } from '../../utils/fetchApi';

const Search = () => {
  const {searchTerm} = useParams();
   console.log(`${searchTerm}`);
  const {isLoading,isError,error,data:searchItem}=useQuery({
    queryKey:['searchItem'],
    queryFn: ()=> fetchSearch(`${searchTerm}`)
    .then((res)=>{
      console.log(res);
      return res.results;
    }
      ),
  })

  useEffect(()=>{
    searchItem();
  })
  if (isLoading) {
    return (
      <div className="loading">
        <h1>Loading</h1>
      </div>
    );
  } else if (isError) {
    return (
      <div className="error">
        <p>{error.message}</p>
      </div>
    );
  } 
  return (
    <section>
      {
        searchItem.map((item)=>(
         <div key={item.title}>
          <img src={`${Img_URL}${item.poster_path}`} alt="?" />
          <p>{item.overview}</p>
        </div>
        ))
      }
    </section>
  )
    }
export default Search
